module register_adder_clock_gate (
  input CLK,
  input EN,
  input TE,
  output ENCLK
);

  reg ungated_clk;

  always @(posedge CLK) begin
    if (EN && !TE) begin
      ungated_clk <= 1'b1;
    end else begin
      ungated_clk <= 1'b0;
    end
  end

  assign ENCLK = ungated_clk & CLK;

endmodule
